!function(){let e=localStorage.getItem("online")||sessionStorage.getItem("online"),t=JSON.parse(localStorage.getItem(e))||JSON.parse(sessionStorage.getItem(e));document.title+=`${t["name-registration"]} ${String.fromCodePoint(128526)}`}(),document.querySelector("#back").addEventListener("click",(()=>{localStorage.removeItem("redirect"),sessionStorage.removeItem("redirect"),localStorage.removeItem("online"),sessionStorage.removeItem("online"),window.location.assign("/")}));